request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?modelIdType ?msg ?messageName ?messageId WHERE {
  VALUES ?modelIdType { "original" "normalized" }

  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }

  OPTIONAL { ?model tai:originalId ?idOrig . }
  OPTIONAL { ?model tai:normalizedId ?idNorm . }

  FILTER(
    (
      ?modelIdType = "original" && STR(?idOrig) = "1dccc40d34ef40f9b36123e2fbca1a63"
    ) || (
      ?modelIdType = "normalized" && STR(?idNorm) = "1dccc40d34ef40f9b36123e2fbca1a63"
    )
  )

  ?definitions tai:belongsTo ?model .
  OPTIONAL { ?definitions tai:belongsTo ?model . }

  ?msg a bboExt:Message .
  ?msg tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?definitions .

  OPTIONAL { ?msg bbo:name ?messageName . }
  OPTIONAL { ?msg bbo:id ?messageId . }
}
ORDER BY ?messageName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?matchProp ?matchVal ?choreo ?elem ?elemName ?elemType WHERE {
  VALUES ?matchProp { tai:originalId tai:normalizedId tai:organizationId tai:corpusId }
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }

  ?model ?matchProp ?matchVal .
  FILTER(STR(?matchVal) = "1dccc40d34ef40f9b36123e2fbca1a63")

  OPTIONAL {
    ?definitions tai:belongsTo ?model .
    ?choreo tai:belongsTo ?definitions .
  }

  # try message elements and also message-flow edges as a fallback for “messages”
  {
    ?elem a bboExt:Message .
    ?elem tai:belongsTo ?choreo .
  }
  UNION
  {
    ?flow a bboExt:MessageFlow .
    ?flow tai:belongsTo ?choreo .
    BIND(?flow AS ?elem)
  }

  OPTIONAL { ?elem bbo:name ?elemName . }
  OPTIONAL { ?elem a ?elemType . }
}
ORDER BY ?matchProp ?elemName
LIMIT 25
